mapper.select:
select count(distinct d.doc_id) from appr_doc d where d.emp_id = #{empId} or exists (select 1 from appr_line where doc_id = d.doc_id and emp_id = #{empId})
and d.doc_status = #{searchStatus}
and ( d.doc_id like '%' || #{searchKeyword} || '%' or d.doc_title like '%' || #{searchKeyword} || '%' or (select emp_name from employee where emp_id = d.emp_id) like '%' || #{searchKeyword} || '%' )

mapper.update:
update
	appr_doc
set
	doc_status = #{docStatus}
where
	doc_id = #{docId}
